(32, 2, 0, 0, 7, 0, 'Emergency Medical Technician', 0, 0, 'â¢	Assist in Intubation with Nursing staff and medical officer in emergency department. \r\nâ¢	Cannula Insertion of patients.  \r\nâ¢	Sample collection in emergency and Procedure room. \r\nâ¢	Do Catherization \r\nâ¢	Assist in Central line insertion. \r\nâ¢	Do spirometery test. \r\nâ¢	Do uroflowmetry test. \r\nâ¢	Respond swiftly to emergency calls and administer emergency first aid and life support for the patient until they reach the hospital.\r\nâ¢	Take complete handover of his/her assigned staff.\r\nâ¢	Ensure cleanliness and sanitation of the unit.\r\nâ¢	Operate medical machinery like ECG, defibrillators.\r\nâ¢	Administer injections or medications when required.\r\n', 'â¢	Assist in Intubation with Nursing staff and medical officer in emergency department. \r\nâ¢	Cannula Insertion of patients.  \r\nâ¢	Sample collection in emergency and Procedure room. \r\nâ¢	Do Catherization \r\nâ¢	Assist in Central line insertion. \r\nâ¢	Do spirometery test. \r\nâ¢	Do uroflowmetry test. \r\nâ¢	Respond swiftly to emergency calls and administer emergency first aid and life support for the patient until they reach the hospital.\r\nâ¢	Take complete handover of his/her assigned staff.\r\nâ¢	Ensure cleanliness and sanitation of the unit.\r\nâ¢	Operate medical machinery like ECG, defibrillators.\r\nâ¢	Administer injections or medications when required.\r\n', 0, 1, 0, NULL, NULL, 0, NULL, 0),
(33, 2, 0, 2, 8, 0, 'Clinical Floor Coordinator', 0, 0, 'â¢	Coordination rounds- To assist rounds.\r\nâ¢	 To ensure sending of blood and radiological samples, collection of reports and data entry.\r\nâ¢	To coordinate for cross consultations.\r\nâ¢	To ensure shifting of Patients between different wards.\r\nâ¢	To coordinate admission and discharge process.\r\n\r\n', '		Coordination rounds- To assist rounds.\r\nâ¢	 To ensure sending of blood and radiological samples, collection of reports and data entry.\r\nâ¢	To coordinate for cross consultations.\r\nâ¢	To ensure shifting of Patients between different wards.\r\nâ¢	To coordinate admission and discharge process.\r\n\r\n', 0, 1, 0, NULL, NULL, 0, NULL, 0),
